const app = express();
app.use(helmet());
app.use(cors());
app.use(express.json());
app.use(pinoHttp({ logger }));
app.use(rateLimit({ windowMs: 60_000, max: 100 }));
app.use('/api', routes);                                    // r1: routes
app.use((req, res) => res.status(404).json({...}));          // 404
app.use(errorHandler);                                       // r1+r2: last

process.on('SIGTERM', shutdown);
process.on('SIGINT', shutdown);
async function shutdown() {
  server.close(async () => {
    await db.end();
    process.exit(0);
  });
  setTimeout(() => process.exit(1), 15_000).unref();
}

const app = express();
app.use(errorHandler);                                       // r2 violated
app.use(express.json());
app.post('/x', (req, res) => {
  if (!req.body.email) {
    res.status(400).json({ error: 'bad' });                   // r5 violated
  }
});
